const body = $input.first().json.body || $input.first().json;
const { action, username, password, filename, content } = body;

if (!username || !password) {
  return [{ json: { success: false, error: 'Identifiants manquants' } }];
}

const baseUrl = `https://nuage.apps.education.fr/remote.php/dav/files/${encodeURIComponent(username)}/Mentoria/`;
const manifestUrl = baseUrl + 'manifest.json';
const auth = 'Basic ' + Buffer.from(`${username}:${password}`).toString('base64');

const httpGet = async (url, extraHeaders) => {
  return await this.helpers.httpRequest({
    method: 'GET', url,
    headers: { 'Authorization': auth, ...(extraHeaders || {}) },
    returnFullResponse: true, ignoreHttpStatusErrors: true
  });
};

const httpPut = async (url, data) => {
  return await this.helpers.httpRequest({
    method: 'PUT', url,
    headers: { 'Authorization': auth, 'Content-Type': 'application/json' },
    body: typeof data === 'string' ? data : JSON.stringify(data),
    returnFullResponse: true, ignoreHttpStatusErrors: true
  });
};

const httpDelete = async (url) => {
  return await this.helpers.httpRequest({
    method: 'DELETE', url,
    headers: { 'Authorization': auth },
    returnFullResponse: true, ignoreHttpStatusErrors: true
  });
};

const getManifest = async () => {
  const r = await httpGet(manifestUrl);
  if (r.statusCode === 200) {
    try { return typeof r.body === 'string' ? JSON.parse(r.body) : (Array.isArray(r.body) ? r.body : []); }
    catch { return []; }
  }
  return [];
};

const saveManifest = async (list) => {
  await httpPut(manifestUrl, JSON.stringify(list));
};

try {

  // ── TEST : vérification identifiants via OCS ──
  if (action === 'test') {
    const r = await httpGet(
      'https://nuage.apps.education.fr/ocs/v1.php/cloud/user?format=json',
      { 'OCS-APIREQUEST': 'true' }
    );
    if (r.statusCode === 401 || r.statusCode === 403) {
      return [{ json: { success: false, error: 'Identifiants invalides — vérifiez votre mot de passe d\'application.' } }];
    }
    if (r.statusCode !== 200) {
      return [{ json: { success: false, error: 'Erreur connexion Nuage: ' + r.statusCode } }];
    }
    // Crée le dossier Mentoria si besoin (MKCOL — ignoré si déjà existant)
    try {
      await this.helpers.httpRequest({
        method: 'MKCOL', url: baseUrl,
        headers: { 'Authorization': auth },
        returnFullResponse: true, ignoreHttpStatusErrors: true
      });
    } catch(e) { /* dossier existe déjà — normal */ }
    // Initialise le manifest si vide
    const manifest = await getManifest();
    if (!Array.isArray(manifest) || manifest.length === 0) {
      await saveManifest([]);
    }
    return [{ json: { success: true, action: 'test' } }];
  }

  // ── LIST : lit le manifest ──
  if (action === 'list') {
    const manifest = await getManifest();
    return [{ json: { success: true, files: manifest.map(n => ({ name: n })) } }];
  }

  // ── READ : lit un fichier bot ──
  if (action === 'read') {
    const r = await httpGet(baseUrl + encodeURIComponent(filename));
    if (r.statusCode === 404) return [{ json: { success: false, error: 'Fichier introuvable' } }];
    if (r.statusCode === 401) return [{ json: { success: false, error: 'Session expirée — reconnectez-vous' } }];
    try {
      const parsed = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
      return [{ json: { success: true, content: parsed } }];
    } catch(e) {
      return [{ json: { success: false, error: 'Fichier corrompu : ' + e.message } }];
    }
  }

  // ── WRITE : enregistre un fichier bot + met à jour le manifest ──
  if (action === 'write') {
    const data = typeof content === 'string' ? content : JSON.stringify(content, null, 2);
    const r = await httpPut(baseUrl + encodeURIComponent(filename), data);
    if (r.statusCode === 409) {
      return [{ json: { success: false, error: 'Dossier Mentoria introuvable. Reconnectez-vous pour le créer.' } }];
    }
    if (r.statusCode === 401) return [{ json: { success: false, error: 'Session expirée' } }];
    // Mise à jour du manifest
    const manifest = await getManifest();
    if (!manifest.includes(filename)) {
      manifest.push(filename);
      await saveManifest(manifest);
    }
    return [{ json: { success: true, action: 'write' } }];
  }

  // ── DELETE : supprime un fichier bot + met à jour le manifest ──
  if (action === 'delete') {
    await httpDelete(baseUrl + encodeURIComponent(filename));
    const manifest = await getManifest();
    await saveManifest(manifest.filter(n => n !== filename));
    return [{ json: { success: true, action: 'delete' } }];
  }

  return [{ json: { success: false, error: 'Action inconnue : ' + action } }];

} catch(e) {
  return [{ json: { success: false, error: e.message } }];
}
